using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI.Chat;
using Microsoft.Extensions.AI;

// Test 1: Create OpenAI client and convert to IChatClient
var apiKey = "test-key";
var openAiClient = new ChatClient("gpt-4o", apiKey);
var chatClient = openAiClient.AsIChatClient();

// Test 2: Create ChatClientAgent with simple constructor
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: "You are a helpful assistant",
    name: "TestAgent"
);

// Test 3: Create ChatClientAgent with options
var options = new ChatClientAgentOptions
{
    Name = "TestAgent2",
    Description = "A test agent"
};
var agent2 = new ChatClientAgent(chatClient, options);

// Test 4: Run the agent with text
var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync("Hello", session);

// Test 5: Run streaming
var streamResponse = agent.RunStreamingAsync("Hello", session);
await foreach (var update in streamResponse)
{
    Console.WriteLine($"Update: {update}");
}

// Test 6: Run with ChatClientAgentRunOptions
var runOptions = new ChatClientAgentRunOptions();
var response2 = await agent.RunAsync("Test", session, runOptions);

// Test 7: Create extension method AsAIAgent
var agentFromExt = chatClient.AsAIAgent();

EOF
